/**
 * SMS notification adapter.
 *
 * Implements the NotificationAdapter interface for SMS delivery.
 * Validates phone number recipients, formats messages for SMS
 * character limits, and records sent messages for testing/auditing.
 *
 * ## Features
 *
 * - **Phone number validation**: Validates that the recipient is a
 *   well-formed phone number (E.164 format or common domestic formats).
 * - **Message formatting**: Truncates notification body to SMS-friendly
 *   length (160 characters), appending an ellipsis when truncated.
 * - **Priority prefix**: Prepends a priority tag for `high` and `urgent`
 *   notifications so the recipient sees urgency immediately.
 *
 * ## Usage
 *
 * ```typescript
 * const smsAdapter = new SmsAdapter();
 * notificationService.registerAdapter(smsAdapter);
 * ```
 *
 * ## Message format
 *
 * The SMS message is composed as:
 * ```
 * [URGENT] Order Confirmation: ORD-001 — Your order has been placed.
 * ```
 *
 * Priority prefix is included only for `high` and `urgent` notifications.
 * Subject and body are joined with " — " and truncated to 160 characters.
 *
 * ## Replacing with a real provider
 *
 * To use a real SMS provider (Twilio, AWS SNS, etc.), modify the
 * `send()` method to call the provider API after message formatting.
 * Wrap external API errors and return `{ success: false, error: '...' }`.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type {
  NotificationPayload,
  NotificationResult,
  NotificationType,
  NotificationPriority,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/** Maximum SMS message length (standard single-segment SMS). */
const MAX_SMS_LENGTH = 160;

/**
 * A sent SMS record stored by the adapter.
 * Includes the phone number, formatted message, and delivery metadata.
 * Useful for testing and asserting on sent messages.
 */
export interface SentSms {
  /** Unique message identifier (e.g., `sms-0001`). */
  messageId: string;

  /** The recipient phone number. */
  to: string;

  /** The original notification subject. */
  subject: string;

  /** The original notification body (untruncated). */
  body: string;

  /** The formatted SMS message (truncated to SMS length). */
  message: string;

  /** Notification priority level. */
  priority: NotificationPriority;

  /** When the SMS was "sent" (recorded). */
  sentAt: Date;
}

/**
 * Phone number validation — accepts E.164 format and common domestic formats.
 *
 * Accepted formats:
 * - E.164: `+14155551234`
 * - With spaces/dashes/dots: `+1 415-555-1234`, `415.555.1234`
 * - Parenthetical area code: `(415) 555-1234`
 * - Minimum 7 digits (local), maximum 15 digits (E.164 max)
 */
const PHONE_REGEX = /^\+?[\d\s\-().]{7,20}$/;

/** Minimum number of actual digits in a valid phone number. */
const MIN_DIGITS = 7;

let nextMessageId = 1;

function generateMessageId(): string {
  return `sms-${String(nextMessageId++).padStart(4, '0')}`;
}

/**
 * Reset the message ID counter. For testing only.
 */
export function resetSmsMessageIdCounter(): void {
  nextMessageId = 1;
}

export class SmsAdapter implements NotificationAdapter {
  readonly type: NotificationType = 'sms';
  private logger = new Logger('SmsAdapter');
  private sentMessages: SentSms[] = [];

  /**
   * Validate a phone number string.
   *
   * The phone number must contain at least 7 digits and match
   * common phone number formats (E.164, domestic with separators, etc.).
   *
   * @param phoneNumber - The phone number string to validate.
   * @returns true if the phone number is valid for SMS delivery.
   */
  validatePhoneNumber(phoneNumber: string): boolean {
    const trimmed = phoneNumber.trim();
    if (!PHONE_REGEX.test(trimmed)) {
      return false;
    }

    // Count actual digits — must have at least MIN_DIGITS
    const digitCount = trimmed.replace(/\D/g, '').length;
    return digitCount >= MIN_DIGITS;
  }

  /**
   * Format a notification payload into an SMS message string.
   *
   * The message is composed from the subject and body, joined with " — ".
   * For `high` and `urgent` priority notifications, a priority tag is
   * prepended (e.g., `[URGENT]`). The final message is truncated to
   * 160 characters with an ellipsis if it exceeds the limit.
   *
   * @param payload - The notification payload to format.
   * @returns The formatted SMS message string.
   */
  formatMessage(payload: NotificationPayload): string {
    const priority = payload.priority ?? 'normal';

    let message = '';

    // Prepend priority tag for high/urgent
    if (priority === 'urgent') {
      message += '[URGENT] ';
    } else if (priority === 'high') {
      message += '[HIGH] ';
    }

    // Compose: subject — body
    message += `${payload.subject} — ${payload.body}`;

    // Truncate to SMS length
    if (message.length > MAX_SMS_LENGTH) {
      message = message.substring(0, MAX_SMS_LENGTH - 3) + '...';
    }

    return message;
  }

  /**
   * Send a notification via SMS.
   *
   * Validates the recipient phone number, formats the message, and
   * records the delivery. Returns a failure result if the phone number
   * is invalid. Never throws.
   *
   * @param payload - The notification payload to deliver via SMS.
   * @returns A result indicating delivery success or failure.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    const timestamp = new Date();

    try {
      // 1. Validate phone number
      const phoneNumber = payload.recipient.trim();
      if (!this.validatePhoneNumber(phoneNumber)) {
        this.logger.error(`Invalid phone number: ${payload.recipient}`);
        return {
          success: false,
          error: `Invalid phone number: ${payload.recipient}`,
          timestamp,
        };
      }

      // 2. Format message
      const message = this.formatMessage(payload);

      // 3. Generate ID and store sent SMS
      const messageId = generateMessageId();

      const sentSms: SentSms = {
        messageId,
        to: phoneNumber,
        subject: payload.subject,
        body: payload.body,
        message,
        priority: payload.priority ?? 'normal',
        sentAt: timestamp,
      };

      this.sentMessages.push(sentSms);
      this.logger.info(
        `SMS sent: ${messageId} to ${phoneNumber} — "${payload.subject}"`,
      );

      return {
        success: true,
        messageId,
        timestamp,
      };
    } catch (err) {
      const errorMessage =
        err instanceof Error ? err.message : 'Unknown SMS delivery error';
      this.logger.error(
        `SMS delivery failed for ${payload.recipient}: ${errorMessage}`,
      );

      return {
        success: false,
        error: errorMessage,
        timestamp,
      };
    }
  }

  /**
   * Get all SMS messages sent through this adapter. Useful for testing.
   */
  getSentMessages(): SentSms[] {
    return [...this.sentMessages];
  }

  /**
   * Get SMS messages sent to a specific phone number. Useful for testing.
   */
  getSentMessagesTo(phoneNumber: string): SentSms[] {
    return this.sentMessages.filter((m) => m.to === phoneNumber);
  }

  /**
   * Get the count of sent SMS messages.
   */
  getSentMessageCount(): number {
    return this.sentMessages.length;
  }

  /**
   * Clear all sent SMS messages. Useful for testing.
   */
  clearSentMessages(): void {
    this.sentMessages = [];
  }
}

