import { describe, it, expect, beforeEach } from 'vitest';
import {
  SmsAdapter,
  resetSmsMessageIdCounter,
} from '../../src/adapters/sms.adapter.js';
import type {
  SentSms,
} from '../../src/adapters/sms.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

describe('SmsAdapter', () => {
  let adapter: SmsAdapter;

  beforeEach(() => {
    adapter = new SmsAdapter();
    resetSmsMessageIdCounter();
  });

  describe('type', () => {
    it('should have type "sms"', () => {
      expect(adapter.type).toBe('sms');
    });
  });

  // ---------------------------------------------------------------------------
  // validatePhoneNumber
  // ---------------------------------------------------------------------------
  describe('validatePhoneNumber', () => {
    it('should accept an E.164 format number', () => {
      expect(adapter.validatePhoneNumber('+14155551234')).toBe(true);
    });

    it('should accept a domestic number with dashes', () => {
      expect(adapter.validatePhoneNumber('415-555-1234')).toBe(true);
    });

    it('should accept a number with spaces', () => {
      expect(adapter.validatePhoneNumber('+1 415 555 1234')).toBe(true);
    });

    it('should accept a number with parenthetical area code', () => {
      expect(adapter.validatePhoneNumber('(415) 555-1234')).toBe(true);
    });

    it('should accept a number with dots', () => {
      expect(adapter.validatePhoneNumber('415.555.1234')).toBe(true);
    });

    it('should accept an international number', () => {
      expect(adapter.validatePhoneNumber('+442071234567')).toBe(true);
    });

    it('should reject an empty string', () => {
      expect(adapter.validatePhoneNumber('')).toBe(false);
    });

    it('should reject a plain string', () => {
      expect(adapter.validatePhoneNumber('not-a-number')).toBe(false);
    });

    it('should reject an email address', () => {
      expect(adapter.validatePhoneNumber('alice@example.com')).toBe(false);
    });

    it('should reject a number with too few digits', () => {
      expect(adapter.validatePhoneNumber('12345')).toBe(false);
    });

    it('should reject a URL', () => {
      expect(adapter.validatePhoneNumber('https://example.com')).toBe(false);
    });

    it('should handle leading/trailing whitespace', () => {
      expect(adapter.validatePhoneNumber('  +14155551234  ')).toBe(true);
    });

    it('should accept a 7-digit local number', () => {
      expect(adapter.validatePhoneNumber('5551234')).toBe(true);
    });
  });

  // ---------------------------------------------------------------------------
  // formatMessage
  // ---------------------------------------------------------------------------
  describe('formatMessage', () => {
    it('should format a basic message with subject and body', () => {
      const payload: NotificationPayload = {
        type: 'sms',
        recipient: '+14155551234',
        subject: 'Order Confirmation',
        body: 'Your order has been placed.',
        priority: 'normal',
      };

      const result = adapter.formatMessage(payload);

      expect(result).toBe('Order Confirmation — Your order has been placed.');
    });

    it('should prepend [URGENT] for urgent priority', () => {
      const payload: NotificationPayload = {
        type: 'sms',
        recipient: '+14155551234',
        subject: 'Critical Alert',
        body: 'System down.',
        priority: 'urgent',
      };

      const result = adapter.formatMessage(payload);

      expect(result).toContain('[URGENT]');
      expect(result).toBe('[URGENT] Critical Alert — System down.');
    });

    it('should prepend [HIGH] for high priority', () => {
      const payload: NotificationPayload = {
        type: 'sms',
        recipient: '+14155551234',
        subject: 'Important',
        body: 'Action required.',
        priority: 'high',
      };

      const result = adapter.formatMessage(payload);

      expect(result).toContain('[HIGH]');
      expect(result).toBe('[HIGH] Important — Action required.');
    });

    it('should not prepend priority tag for normal priority', () => {
      const payload: NotificationPayload = {
        type: 'sms',
        recipient: '+14155551234',
        subject: 'Info',
        body: 'Just a note.',
        priority: 'normal',
      };

      const result = adapter.formatMessage(payload);

      expect(result).not.toContain('[');
    });

    it('should not prepend priority tag for low priority', () => {
      const payload: NotificationPayload = {
        type: 'sms',
        recipient: '+14155551234',
        subject: 'FYI',
        body: 'Low priority note.',
        priority: 'low',
      };

      const result = adapter.formatMessage(payload);

      expect(result).not.toContain('[');
    });

    it('should default priority to normal when not specified', () => {
      const payload: NotificationPayload = {
        type: 'sms',
        recipient: '+14155551234',
        subject: 'Test',
        body: 'Body.',
      };

      const result = adapter.formatMessage(payload);

      expect(result).not.toContain('[');
      expect(result).toBe('Test — Body.');
    });

    it('should truncate messages longer than 160 characters with ellipsis', () => {
      const payload: NotificationPayload = {
        type: 'sms',
        recipient: '+14155551234',
        subject: 'Long Subject',
        body: 'A'.repeat(200),
        priority: 'normal',
      };

      const result = adapter.formatMessage(payload);

      expect(result.length).toBe(160);
      expect(result).toMatch(/\.\.\.$/);
    });

    it('should not truncate messages at exactly 160 characters', () => {
      // "Test — " is 7 chars; body needs to be 153 chars for exactly 160 total
      const body = 'A'.repeat(153);
      const payload: NotificationPayload = {
        type: 'sms',
        recipient: '+14155551234',
        subject: 'Test',
        body,
        priority: 'normal',
      };

      const result = adapter.formatMessage(payload);

      expect(result.length).toBe(160);
      expect(result).not.toMatch(/\.\.\.$/);
    });

    it('should not truncate short messages', () => {
      const payload: NotificationPayload = {
        type: 'sms',
        recipient: '+14155551234',
        subject: 'Hi',
        body: 'Hello!',
      };

      const result = adapter.formatMessage(payload);

      expect(result).toBe('Hi — Hello!');
      expect(result.length).toBeLessThanOrEqual(160);
    });
  });

  // ---------------------------------------------------------------------------
  // send
  // ---------------------------------------------------------------------------
  describe('send', () => {
    it('should send an SMS successfully to a valid phone number', async () => {
      const result = await adapter.send({
        type: 'sms',
        recipient: '+14155551234',
        subject: 'Order Confirmation: ORD-001',
        body: 'Your order has been placed.',
        priority: 'normal',
      });

      expect(result.success).toBe(true);
      expect(result.messageId).toBe('sms-0001');
      expect(result.timestamp).toBeInstanceOf(Date);
      expect(result.error).toBeUndefined();
    });

    it('should store the sent SMS with all fields', async () => {
      await adapter.send({
        type: 'sms',
        recipient: '+14155551234',
        subject: 'Order Confirmation: ORD-001',
        body: 'Items: Widget x2. Total: $20.00',
        priority: 'high',
      });

      const messages = adapter.getSentMessages();
      expect(messages).toHaveLength(1);

      const sms = messages[0]!;
      expect(sms.to).toBe('+14155551234');
      expect(sms.subject).toBe('Order Confirmation: ORD-001');
      expect(sms.body).toBe('Items: Widget x2. Total: $20.00');
      expect(sms.message).toContain('[HIGH]');
      expect(sms.message).toContain('Order Confirmation: ORD-001');
      expect(sms.message).toContain('Items: Widget x2. Total: $20.00');
      expect(sms.priority).toBe('high');
      expect(sms.messageId).toBe('sms-0001');
      expect(sms.sentAt).toBeInstanceOf(Date);
    });

    it('should fail for an invalid phone number', async () => {
      const result = await adapter.send({
        type: 'sms',
        recipient: 'not-a-phone-number',
        subject: 'Test',
        body: 'Test body',
      });

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid phone number');
      expect(result.error).toContain('not-a-phone-number');
      expect(adapter.getSentMessageCount()).toBe(0);
    });

    it('should fail for an empty recipient', async () => {
      const result = await adapter.send({
        type: 'sms',
        recipient: '',
        subject: 'Test',
        body: 'Test body',
      });

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid phone number');
    });

    it('should fail for an email address as recipient', async () => {
      const result = await adapter.send({
        type: 'sms',
        recipient: 'alice@example.com',
        subject: 'Test',
        body: 'Test body',
      });

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid phone number');
      expect(adapter.getSentMessageCount()).toBe(0);
    });

    it('should trim whitespace from the phone number', async () => {
      await adapter.send({
        type: 'sms',
        recipient: '  +14155551234  ',
        subject: 'Test',
        body: 'Body',
      });

      const messages = adapter.getSentMessages();
      expect(messages).toHaveLength(1);
      expect(messages[0]!.to).toBe('+14155551234');
    });

    it('should default priority to normal when not specified', async () => {
      await adapter.send({
        type: 'sms',
        recipient: '+14155551234',
        subject: 'Test',
        body: 'Body.',
      });

      const messages = adapter.getSentMessages();
      expect(messages[0]!.priority).toBe('normal');
    });

    it('should include priority prefix in message for urgent SMS', async () => {
      await adapter.send({
        type: 'sms',
        recipient: '+14155551234',
        subject: 'Critical Alert',
        body: 'System down.',
        priority: 'urgent',
      });

      const messages = adapter.getSentMessages();
      expect(messages[0]!.message).toContain('[URGENT]');
    });

    it('should generate sequential message IDs', async () => {
      await adapter.send({
        type: 'sms',
        recipient: '+14155551234',
        subject: 'First',
        body: '1',
      });
      await adapter.send({
        type: 'sms',
        recipient: '+14155551234',
        subject: 'Second',
        body: '2',
      });
      await adapter.send({
        type: 'sms',
        recipient: '+14155551234',
        subject: 'Third',
        body: '3',
      });

      const messages = adapter.getSentMessages();
      expect(messages[0]!.messageId).toBe('sms-0001');
      expect(messages[1]!.messageId).toBe('sms-0002');
      expect(messages[2]!.messageId).toBe('sms-0003');
    });

    it('should never throw — return failure result on unexpected errors', async () => {
      const result = await adapter.send({
        type: 'sms',
        recipient: '+14155551234',
        subject: 'Test',
        body: 'Body',
      });

      // The call should not throw
      expect(result).toBeDefined();
      expect(typeof result.success).toBe('boolean');
      expect(result.timestamp).toBeInstanceOf(Date);
    });
  });

  // ---------------------------------------------------------------------------
  // Test helper methods
  // ---------------------------------------------------------------------------
  describe('getSentMessages', () => {
    it('should return an empty array initially', () => {
      expect(adapter.getSentMessages()).toEqual([]);
    });

    it('should return a copy, not the internal array', async () => {
      await adapter.send({
        type: 'sms',
        recipient: '+14155551234',
        subject: 'Test',
        body: 'Body',
      });

      const messages1 = adapter.getSentMessages();
      const messages2 = adapter.getSentMessages();
      expect(messages1).not.toBe(messages2);
      expect(messages1).toEqual(messages2);
    });
  });

  describe('getSentMessagesTo', () => {
    it('should filter messages by phone number', async () => {
      await adapter.send({
        type: 'sms',
        recipient: '+14155551234',
        subject: 'To A',
        body: 'Hi A.',
      });
      await adapter.send({
        type: 'sms',
        recipient: '+14155559999',
        subject: 'To B',
        body: 'Hi B.',
      });
      await adapter.send({
        type: 'sms',
        recipient: '+14155551234',
        subject: 'Another to A',
        body: 'Hi again.',
      });

      expect(adapter.getSentMessagesTo('+14155551234')).toHaveLength(2);
      expect(adapter.getSentMessagesTo('+14155559999')).toHaveLength(1);
      expect(adapter.getSentMessagesTo('+10000000000')).toHaveLength(0);
    });
  });

  describe('getSentMessageCount', () => {
    it('should return 0 initially', () => {
      expect(adapter.getSentMessageCount()).toBe(0);
    });

    it('should count sent messages correctly', async () => {
      await adapter.send({
        type: 'sms',
        recipient: '+14155551234',
        subject: 'One',
        body: '1',
      });
      await adapter.send({
        type: 'sms',
        recipient: '+14155559999',
        subject: 'Two',
        body: '2',
      });

      expect(adapter.getSentMessageCount()).toBe(2);
    });

    it('should not count failed sends', async () => {
      await adapter.send({
        type: 'sms',
        recipient: 'invalid',
        subject: 'Fail',
        body: 'Fail',
      });

      expect(adapter.getSentMessageCount()).toBe(0);
    });
  });

  describe('clearSentMessages', () => {
    it('should clear all sent messages', async () => {
      await adapter.send({
        type: 'sms',
        recipient: '+14155551234',
        subject: 'Test',
        body: 'Body',
      });

      expect(adapter.getSentMessageCount()).toBe(1);

      adapter.clearSentMessages();

      expect(adapter.getSentMessageCount()).toBe(0);
      expect(adapter.getSentMessages()).toEqual([]);
    });
  });

  // ---------------------------------------------------------------------------
  // Integration: full pipeline
  // ---------------------------------------------------------------------------
  describe('full send pipeline', () => {
    it('should compose a complete SMS for an order notification', async () => {
      const result = await adapter.send({
        type: 'sms',
        recipient: '+14155551234',
        subject: 'Order Confirmation: ORD-42',
        body: 'Your order has been placed. Items: Widget x2, Gadget x1. Total: $45.00',
        priority: 'normal',
      });

      expect(result.success).toBe(true);

      const sms = adapter.getSentMessages()[0]!;
      expect(sms.to).toBe('+14155551234');
      expect(sms.priority).toBe('normal');
      expect(sms.message).toContain('Order Confirmation: ORD-42');
      expect(sms.message).toContain('Widget x2, Gadget x1');
      expect(sms.message).toContain('$45.00');
      expect(sms.message).not.toContain('[');
      expect(sms.message.length).toBeLessThanOrEqual(160);
    });

    it('should compose a high-priority SMS with priority prefix', async () => {
      const result = await adapter.send({
        type: 'sms',
        recipient: '+14155559999',
        subject: 'Order Update: ORD-99',
        body: 'Your order status has changed from confirmed to shipped.',
        priority: 'high',
      });

      expect(result.success).toBe(true);

      const sms = adapter.getSentMessages()[0]!;
      expect(sms.priority).toBe('high');
      expect(sms.message).toContain('[HIGH]');
      expect(sms.message).toContain('Order Update: ORD-99');
      expect(sms.message).toContain('confirmed to shipped');
      expect(sms.message.length).toBeLessThanOrEqual(160);
    });
  });

  // ---------------------------------------------------------------------------
  // Integration with NotificationService pattern
  // ---------------------------------------------------------------------------
  describe('adapter interface compliance', () => {
    it('should implement the NotificationAdapter interface', () => {
      // Verify the adapter has the required properties and methods
      expect(adapter.type).toBe('sms');
      expect(typeof adapter.send).toBe('function');
    });

    it('should work with dispatchNotification-style payloads', async () => {
      // Simulates how NotificationService calls the adapter
      const payload: NotificationPayload = {
        type: 'sms',
        recipient: '+14155551234',
        subject: 'Order Confirmation: ORD-001',
        body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
        priority: 'normal',
      };

      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.messageId).toBeDefined();
      expect(result.timestamp).toBeInstanceOf(Date);
    });
  });
});

